-- ============================================================
-- post_categories (10 records)
-- ============================================================

-- ============================================================
-- posts (100 records — 10 per category)
-- ============================================================

-- Category 1: Technology

-- Category 2: Travel

-- Category 3: Food & Cooking

-- Category 4: Health & Fitness

-- Category 5: Business

-- Category 6: Entertainment

-- Category 7: Sports

-- Category 8: Science

-- Category 9: Education

-- Category 10: Lifestyle

-- ============================================================
-- post_tags (sample tags per post)
-- ============================================================
SELECT p.id, t.tag
FROM posts p
CROSS JOIN LATERAL (
    VALUES
        (CASE WHEN p.category_id = 1  THEN 'technology'   WHEN p.category_id = 2  THEN 'travel'       WHEN p.category_id = 3  THEN 'food'
              WHEN p.category_id = 4  THEN 'health'       WHEN p.category_id = 5  THEN 'business'     WHEN p.category_id = 6  THEN 'entertainment'
              WHEN p.category_id = 7  THEN 'sports'       WHEN p.category_id = 8  THEN 'science'      WHEN p.category_id = 9  THEN 'education'
              ELSE 'lifestyle' END),
        (CASE WHEN p.category_id IN (1,8)  THEN 'trending'  WHEN p.category_id IN (2,10) THEN 'popular'
              WHEN p.category_id IN (3,4)  THEN 'wellness'  WHEN p.category_id IN (5,9)  THEN 'knowledge'
              ELSE 'featured' END),
        'english'
) AS t(tag)
WHERE p.status = 'ACT';
